import{c as a,Q as e,j as n,m as d}from"./chunks/framework.ga0D1uIo.js";const b=JSON.parse('{"title":"第二十二章：其他预训练模型","description":"","frontmatter":{},"headers":[],"relativePath":"pretrained-models/other-models.md","filePath":"pretrained-models/other-models.md","lastUpdated":1779795405000}'),r={name:"pretrained-models/other-models.md"};function s(o,t,l,i,h,p){return e(),n("div",null,[...t[0]||(t[0]=[d(`<h1 id="第二十二章-其他预训练模型" tabindex="-1">第二十二章：其他预训练模型 <a class="header-anchor" href="#第二十二章-其他预训练模型" aria-label="Permalink to &quot;第二十二章：其他预训练模型&quot;">​</a></h1><p>除了 GPT 和 BERT，还有许多重要的预训练模型。本章介绍几个代表性的工作。</p><hr><h2 id="t5-2019" tabindex="-1">T5（2019） <a class="header-anchor" href="#t5-2019" aria-label="Permalink to &quot;T5（2019）&quot;">​</a></h2><h3 id="核心思想" tabindex="-1">核心思想 <a class="header-anchor" href="#核心思想" aria-label="Permalink to &quot;核心思想&quot;">​</a></h3><p>T5（Text-to-Text Transfer Transformer）由 Google 提出，将<strong>所有 NLP 任务统一为文本到文本的格式</strong>。</p><h3 id="统一框架" tabindex="-1">统一框架 <a class="header-anchor" href="#统一框架" aria-label="Permalink to &quot;统一框架&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>分类任务：</span></span>
<span class="line"><span>  输入：&quot;sentiment: 这个电影很好看&quot;</span></span>
<span class="line"><span>  输出：&quot;正面&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>翻译任务：</span></span>
<span class="line"><span>  输入：&quot;translate English to French: cheese&quot;</span></span>
<span class="line"><span>  输出：&quot;fromage&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>摘要任务：</span></span>
<span class="line"><span>  输入：&quot;summarize: 一篇很长的文章...&quot;</span></span>
<span class="line"><span>  输出：&quot;文章的摘要...&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>问答任务：</span></span>
<span class="line"><span>  输入：&quot;question: 谁是法国总统? context: 法国总统是马克龙...&quot;</span></span>
<span class="line"><span>  输出：&quot;马克龙&quot;</span></span></code></pre></div><h3 id="模型架构" tabindex="-1">模型架构 <a class="header-anchor" href="#模型架构" aria-label="Permalink to &quot;模型架构&quot;">​</a></h3><p>T5 使用 Transformer 的<strong>编码器-解码器</strong>架构（与原始 Transformer 相同）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入文本 → 编码器 → 解码器 → 输出文本</span></span></code></pre></div><h3 id="预训练任务" tabindex="-1">预训练任务 <a class="header-anchor" href="#预训练任务" aria-label="Permalink to &quot;预训练任务&quot;">​</a></h3><p>T5 使用<strong>跨度损坏</strong>（Span Corruption）作为预训练任务：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入：&quot;我 喜欢 &lt;X&gt; 处理 &lt;Y&gt; 是 人工智能&quot;</span></span>
<span class="line"><span>输出：&quot;自然 语言 &lt;X&gt; 技术 &lt;Y&gt; 的 分支 &lt;Z&gt;&quot;</span></span></code></pre></div><p>随机遮盖连续的文本片段，让模型预测被遮盖的内容。</p><h3 id="模型规模" tabindex="-1">模型规模 <a class="header-anchor" href="#模型规模" aria-label="Permalink to &quot;模型规模&quot;">​</a></h3><table tabindex="0"><thead><tr><th>版本</th><th>参数量</th></tr></thead><tbody><tr><td>T5-Small</td><td>60M</td></tr><tr><td>T5-Base</td><td>220M</td></tr><tr><td>T5-Large</td><td>770M</td></tr><tr><td>T5-3B</td><td>3B</td></tr><tr><td>T5-11B</td><td>11B</td></tr></tbody></table><hr><h2 id="xlnet-2019" tabindex="-1">XLNet（2019） <a class="header-anchor" href="#xlnet-2019" aria-label="Permalink to &quot;XLNet（2019）&quot;">​</a></h2><h3 id="核心创新" tabindex="-1">核心创新 <a class="header-anchor" href="#核心创新" aria-label="Permalink to &quot;核心创新&quot;">​</a></h3><p>XLNet 结合了自回归（GPT）和自编码（BERT）的优点，提出了<strong>排列语言模型</strong>。</p><h3 id="排列语言模型" tabindex="-1">排列语言模型 <a class="header-anchor" href="#排列语言模型" aria-label="Permalink to &quot;排列语言模型&quot;">​</a></h3><p>传统语言模型按固定顺序预测：</p><p>$$P(x_1, x_2, x_3) = P(x_1) P(x_2|x_1) P(x_3|x_1, x_2)$$</p><p>排列语言模型随机打乱顺序：</p><p>$$P(x_1, x_2, x_3) = P(x_3) P(x_1|x_3) P(x_2|x_1, x_3)$$</p><p>通过遍历所有可能的排列，XLNet 可以捕捉双向的上下文信息。</p><h3 id="与-bert-的区别" tabindex="-1">与 BERT 的区别 <a class="header-anchor" href="#与-bert-的区别" aria-label="Permalink to &quot;与 BERT 的区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>BERT</th><th>XLNet</th></tr></thead><tbody><tr><td>预训练任务</td><td>掩码语言模型</td><td>排列语言模型</td></tr><tr><td>独立性假设</td><td>假设被遮盖的词相互独立</td><td>无独立性假设</td></tr><tr><td>输入噪声</td><td>[MASK] token（微调时不存在）</td><td>无噪声</td></tr></tbody></table><hr><h2 id="electra-2020" tabindex="-1">ELECTRA（2020） <a class="header-anchor" href="#electra-2020" aria-label="Permalink to &quot;ELECTRA（2020）&quot;">​</a></h2><h3 id="核心思想-1" tabindex="-1">核心思想 <a class="header-anchor" href="#核心思想-1" aria-label="Permalink to &quot;核心思想&quot;">​</a></h3><p>ELECTRA 提出了一种更高效的预训练任务：<strong>替换 token 检测</strong>（Replaced Token Detection）。</p><h3 id="工作流程" tabindex="-1">工作流程 <a class="header-anchor" href="#工作流程" aria-label="Permalink to &quot;工作流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 生成器（小型 MLM）生成替换 token</span></span>
<span class="line"><span>   输入：我 爱 [MASK] 语言 处理</span></span>
<span class="line"><span>   输出：我 爱 计算 语言 处理（&quot;自然&quot;被替换为&quot;计算&quot;）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 判别器判断每个 token 是否被替换</span></span>
<span class="line"><span>   输入：我 爱 计算 语言 处理</span></span>
<span class="line"><span>   标签：真 真 假 真 真</span></span></code></pre></div><h3 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h3><table tabindex="0"><thead><tr><th>优势</th><th>说明</th></tr></thead><tbody><tr><td>更高效</td><td>所有 token 都参与训练（不只是 15% 的 [MASK]）</td></tr><tr><td>更快收敛</td><td>二分类任务比生成任务更容易学习</td></tr><tr><td>效果好</td><td>在相同计算预算下性能优于 BERT</td></tr></tbody></table><hr><h2 id="多语言模型" tabindex="-1">多语言模型 <a class="header-anchor" href="#多语言模型" aria-label="Permalink to &quot;多语言模型&quot;">​</a></h2><h3 id="mbert-多语言-bert" tabindex="-1">mBERT（多语言 BERT） <a class="header-anchor" href="#mbert-多语言-bert" aria-label="Permalink to &quot;mBERT（多语言 BERT）&quot;">​</a></h3><ul><li>在 104 种语言的维基百科上训练</li><li>所有语言共享同一个词表和模型参数</li><li>可以进行<strong>零样本跨语言迁移</strong>：在英文上微调，直接用于中文</li></ul><h3 id="xlm-roberta" tabindex="-1">XLM-RoBERTa <a class="header-anchor" href="#xlm-roberta" aria-label="Permalink to &quot;XLM-RoBERTa&quot;">​</a></h3><ul><li>在 2.5TB 的 CommonCrawl 数据上训练（100 种语言）</li><li>性能显著优于 mBERT</li><li>是多语言 NLP 任务的首选模型</li></ul><hr><h2 id="长文本模型" tabindex="-1">长文本模型 <a class="header-anchor" href="#长文本模型" aria-label="Permalink to &quot;长文本模型&quot;">​</a></h2><h3 id="longformer" tabindex="-1">Longformer <a class="header-anchor" href="#longformer" aria-label="Permalink to &quot;Longformer&quot;">​</a></h3><p>解决 Transformer 的 $O(n^2)$ 复杂度问题：</p><table tabindex="0"><thead><tr><th>注意力类型</th><th>复杂度</th><th>适用位置</th></tr></thead><tbody><tr><td>全局注意力</td><td>$O(n^2)$</td><td>特殊 token（[CLS]）</td></tr><tr><td>滑动窗口注意力</td><td>$O(n)$</td><td>普通 token</td></tr></tbody></table><h3 id="bigbird" tabindex="-1">BigBird <a class="header-anchor" href="#bigbird" aria-label="Permalink to &quot;BigBird&quot;">​</a></h3><p>使用<strong>随机注意力 + 窗口注意力 + 全局注意力</strong>的组合，支持最长 4096 token 的输入。</p><hr><h2 id="中文预训练模型" tabindex="-1">中文预训练模型 <a class="header-anchor" href="#中文预训练模型" aria-label="Permalink to &quot;中文预训练模型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模型</th><th>机构</th><th>特点</th></tr></thead><tbody><tr><td>ERNIE</td><td>百度</td><td>融合知识图谱</td></tr><tr><td>MacBERT</td><td>哈工大</td><td>同义词替换掩码</td></tr><tr><td>RoBERTa-wwm</td><td>哈工大</td><td>全词掩码</td></tr><tr><td>ChatGLM</td><td>清华</td><td>对话模型</td></tr><tr><td>Qwen</td><td>阿里</td><td>大语言模型</td></tr><tr><td>DeepSeek</td><td>DeepSeek</td><td>开源大模型</td></tr></tbody></table><hr><h2 id="模型选择指南" tabindex="-1">模型选择指南 <a class="header-anchor" href="#模型选择指南" aria-label="Permalink to &quot;模型选择指南&quot;">​</a></h2><table tabindex="0"><thead><tr><th>任务类型</th><th>推荐模型</th></tr></thead><tbody><tr><td>英文分类</td><td>RoBERTa, DeBERTa</td></tr><tr><td>中文分类</td><td>RoBERTa-wwm-ext, MacBERT</td></tr><tr><td>多语言任务</td><td>XLM-RoBERTa</td></tr><tr><td>文本生成</td><td>GPT 系列, T5</td></tr><tr><td>资源受限</td><td>DistilBERT, ALBERT</td></tr><tr><td>长文本</td><td>Longformer, BigBird</td></tr><tr><td>问答</td><td>BERT, RoBERTa</td></tr></tbody></table><hr><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模型</th><th>核心创新</th></tr></thead><tbody><tr><td>T5</td><td>统一的文本到文本框架</td></tr><tr><td>XLNet</td><td>排列语言模型</td></tr><tr><td>ELECTRA</td><td>替换 token 检测</td></tr><tr><td>mBERT/XLM-R</td><td>多语言预训练</td></tr><tr><td>Longformer</td><td>高效长文本处理</td></tr></tbody></table><p>这些模型从不同角度推动了预训练模型的发展，为后续的大语言模型奠定了基础。</p>`,60)])])}const u=a(r,[["render",s]]);export{b as __pageData,u as default};
